import requests
import json

def recursive_scrape_tool(url: str, max_depth: int = 2, max_pages: int = 10) -> str:
    """
    Llama al backend RAG para iniciar un crawling recursivo de la web especificada.
    """
    payload = {
        "url": url,
        "max_depth": max_depth,
        "max_pages": max_pages
    }

    # La URL interna del backend dentro de la red Docker es http://rag-backend:8000
    # Pero si OpenWebUI ejecuta esto, puede que necesite la URL accesible desde el contenedor de OpenWebUI.
    # Asumimos que la tool corre en el contexto de OpenWebUI que tiene acceso a 'rag-backend'.

    api_url = "http://rag-backend:8000/api/scrape/recursive"

    try:
        response = requests.post(api_url, json=payload, timeout=5)
        if response.status_code == 200:
            data = response.json()
            return json.dumps(data, ensure_ascii=False)
        else:
            return f"Error {response.status_code}: {response.text}"
    except Exception as e:
        return f"Error de conexión: {str(e)}"
